t.script:
document.addEventListener('DOMContentLoaded', function() {
    var otpModal = null;
    var currentFormData = null;
    var timerInterval = null;
    var countdown = 300;

    var modalEl = document.getElementById('otp-modal');
    if (modalEl && typeof bootstrap !== 'undefined') otpModal = new bootstrap.Modal(modalEl);

    // Password toggle
    ['togglePassword1', 'togglePassword2'].forEach(function(id) {
        var btn = document.getElementById(id);
        if (btn) {
            btn.addEventListener('click', function() {
                var input = this.previousElementSibling;
                var type = input.type === 'password' ? 'text' : 'password';
                input.type = type;
                this.querySelector('i').className = type === 'password' ? 'fas fa-eye-slash' : 'fas fa-eye';
            });
        }
    });

    // Password validation
    var pw = document.getElementById('password');
    if (pw) {
        pw.addEventListener('input', function() {
            var v = this.value;
            updateReq('req-length', v.length >= 8);
            updateReq('req-uppercase', /[A-Z]/.test(v));
            updateReq('req-number', /[0-9]/.test(v));
            updateReq('req-special', /[!@#$%^&*(),.?":{}|<>_\-+=\[\]\\;'`~]/.test(v));
        });
    }

    function updateReq(id, valid) {
        var el = document.getElementById(id);
        if (el) {
            var icon = el.querySelector('i');
            if (valid) { el.classList.add('req-valid'); icon.className = 'fa fa-check'; }
            else { el.classList.remove('req-valid'); icon.className = 'fa fa-circle'; }
        }
    }

    // Phone input filter
    var phone = document.getElementById('phone');
    if (phone) phone.addEventListener('input', function() { this.value = this.value.replace(/[^0-9]/g, ''); });

    // Form submit
    var form = document.getElementById('signup-form');
    if (form) {
        form.addEventListener('submit', function(e) {
            e.preventDefault();
            var name = document.getElementById('name').value.trim();
            var email = document.getElementById('email').value.trim();
            var phoneVal = document.getElementById('phone').value.trim();
            var password = document.getElementById('password').value;
            var confirmPassword = document.getElementById('confirm_password').value;
            var terms = document.getElementById('terms').checked;

            if (!name || !email || !phoneVal || !password || !confirmPassword || !terms) { showToast('Vui lòng điền đầy đủ thông tin', 'warning'); return; }
            if (password !== confirmPassword) { showToast('Mật khẩu xác nhận không khớp', 'danger'); return; }

            var btn = document.getElementById('signup-submit');
            btn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span>Đang gửi OTP...';
            btn.disabled = true;

            currentFormData = {name: name, email: email, phone: phoneVal, password: password, confirm_password: confirmPassword};

            fetch('/web/signup/otp', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: currentFormData})
            })
            .then(function(r) { return r.json(); })
            .then(function(result) {
                if (result.result && result.result.success) {
                    document.getElementById('otp-phone').textContent = result.result.phone || phoneVal;
                    if (otpModal) otpModal.show();
                    startTimer();
                    document.querySelector('.otp-input').focus();
                } else {
                    showToast(result.result ? result.result.message : 'Có lỗi xảy ra', 'danger');
                }
                btn.innerHTML = '<i class="fas fa-user-plus me-2"></i>Đăng ký';
                btn.disabled = false;
            })
            .catch(function() {
                showToast('Có lỗi xảy ra khi gửi OTP', 'danger');
                btn.innerHTML = '<i class="fas fa-user-plus me-2"></i>Đăng ký';
                btn.disabled = false;
            });
        });
    }

    // OTP inputs
    var otpInputs = document.querySelectorAll('.otp-input');
    otpInputs.forEach(function(input, idx) {
        input.addEventListener('input', function(e) {
            if (!/^\d*$/.test(e.target.value)) { e.target.value = ''; return; }
            if (e.target.value && idx < 5) otpInputs[idx + 1].focus();
            updateVerifyBtn();
        });
        input.addEventListener('keydown', function(e) {
            if (e.key === 'Backspace' && !e.target.value && idx > 0) otpInputs[idx - 1].focus();
        });
    });

    function getOTP() { var otp = ''; otpInputs.forEach(function(i) { otp += i.value; }); return otp; }
    function updateVerifyBtn() { document.getElementById('verify-otp').disabled = getOTP().length !== 6; }
    function clearOTP() { otpInputs.forEach(function(i) { i.value = ''; }); updateVerifyBtn(); }

    function startTimer() {
        countdown = 300;
        updateTimer();
        if (timerInterval) clearInterval(timerInterval);
        timerInterval = setInterval(function() {
            countdown--;
            updateTimer();
            if (countdown <= 0) { clearInterval(timerInterval); showOTPError('Mã OTP đã hết hạn.'); }
        }, 1000);
    }
    function updateTimer() {
        var m = Math.floor(countdown / 60), s = countdown % 60;
        document.getElementById('otp-timer').textContent = (m < 10 ? '0' : '') + m + ':' + (s < 10 ? '0' : '') + s;
    }
    function showOTPError(msg) { var el = document.getElementById('otp-error'); el.textContent = msg; el.classList.remove('d-none'); }
    function hideOTPError() { document.getElementById('otp-error').classList.add('d-none'); }

    // Verify OTP
    var verifyBtn = document.getElementById('verify-otp');
    var otpModalEl = document.getElementById('otp-modal');

    if (verifyBtn) {
        verifyBtn.addEventListener('click', function() {
            var otp = getOTP();
            if (otp.length !== 6) { showOTPError('Vui lòng nhập đủ 6 số'); return; }

            var loading = document.getElementById('otp-loading');
            loading.classList.remove('d-none');
            this.disabled = true;
            hideOTPError();
            // Remove previous states
            otpModalEl.classList.remove('otp-success', 'otp-error');

            fetch('/web/signup/verify-otp', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: {otp: otp}})
            })
            .then(function(r) { return r.json(); })
            .then(function(result) {
                if (result.result && result.result.success) {
                    // Success - add green border
                    otpModalEl.classList.add('otp-success');
                    loading.innerHTML = '<i class="fa fa-check text-success me-2"></i><span class="text-success">' + result.result.message + '</span>';
                    otpInputs.forEach(function(i) { i.classList.add('is-valid'); });
                    setTimeout(function() { window.location.href = result.result.redirect_url; }, 2000);
                } else {
                    // Error - add red border with shake
                    otpModalEl.classList.add('otp-error');
                    otpInputs.forEach(function(i) { i.classList.add('is-invalid'); });
                    showOTPError(result.result ? result.result.message : 'Mã OTP không đúng');
                    loading.classList.add('d-none');
                    verifyBtn.disabled = false;
                    // Remove error state after animation
                    setTimeout(function() { 
                        otpModalEl.classList.remove('otp-error'); 
                        otpInputs.forEach(function(i) { i.classList.remove('is-invalid'); });
                    }, 1500);
                }
            })
            .catch(function() { 
                otpModalEl.classList.add('otp-error');
                showOTPError('Có lỗi xảy ra'); 
                loading.classList.add('d-none'); 
                verifyBtn.disabled = false;
                setTimeout(function() { otpModalEl.classList.remove('otp-error'); }, 1500);
            });
        });
    }

    // Resend OTP
    var resendBtn = document.getElementById('resend-otp');
    if (resendBtn) {
        resendBtn.addEventListener('click', function() {
            if (!currentFormData) return;
            this.disabled = true;
            clearOTP();
            hideOTPError();
            var btn = this;

            fetch('/web/signup/otp', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: currentFormData})
            })
            .then(function(r) { return r.json(); })
            .then(function(result) {
                if (result.result && result.result.success) { startTimer(); document.querySelector('.otp-input').focus(); showToast('Đã gửi lại mã OTP', 'success'); }
                else showOTPError(result.result ? result.result.message : 'Có lỗi xảy ra');
                btn.disabled = false;
            })
            .catch(function() { showOTPError('Có lỗi xảy ra'); btn.disabled = false; });
        });
    }

    function showToast(message, type) {
        var toastEl = document.getElementById('signup-toast');
        var body = document.getElementById('toast-message');
        body.textContent = message;
        toastEl.classList.remove('bg-success', 'bg-danger', 'bg-warning');
        toastEl.classList.add('bg-' + type, 'text-white');
        var toast = new bootstrap.Toast(toastEl, {delay: 5000});
        toast.show();
    }
});
